    fn init(self: *Player) {
        self.pos.x = 0.0
        self.pos.y = 0.0
        self.health = 100
        self.speed = 2.5
        self.alive = true
    }

    fn move(self: *Player, dx: f32, dy: f32) {
        self.pos.x += dx
        self.pos.y += dy
    }

    fn is_alive(self: *Player) -> bool {
        return self.health > 0
    }

    fn take_damage(self: *Player, amount: i32) {
        self.health -= amount
        if self.health <= 0 {
            self.alive = false
        }
    }
}

