        pos: Vec2 { x: 10.0, y: 20.0 },
        health: 100,
        speed: 2.5,
        alive: true,
    }

    -- field access
    sink_x = p.pos.x
    sink_hp = p.health

    -- method calls
    p.move(1.0, 0.0)
    p.take_damage(10)
    sink_hp = p.health

    if p.is_alive() {
        sink_hp = p.health
    }
}

