```pak
use n64.eeprom

const MAGIC: u32 = 0xDEAD1234

@aligned(8)
static buf: [8]u8 = undefined

fn save(score: i32) {
    if not eeprom.present() { return }
    buf[0] = (MAGIC >> 24) as u8
    buf[1] = (MAGIC >> 16) as u8
    buf[2] = (MAGIC >> 8) as u8
    buf[3] = MAGIC as u8
    buf[4] = (score >> 24) as u8
    buf[5] = (score >> 16) as u8
    buf[6] = (score >> 8) as u8
    buf[7] = score as u8
    eeprom.write(0, &buf[0])
}

fn load() -> i32 {
    if not eeprom.present() { return 0 }
    eeprom.read(0, &buf[0])
    let magic: u32 = (buf[0] as u32 << 24) | (buf[1] as u32 << 16)
                   | (buf[2] as u32 << 8) | buf[3] as u32
    if magic != MAGIC { return 0 }
    return (buf[4] as i32 << 24) | (buf[5] as i32 << 16)
         | (buf[6] as i32 << 8) | buf[7] as i32
}
```

