            gs.enemies[i].y = -ENEMY_SIZE
            gs.enemies[i].active = true
            return
        }
    }
}

fn update(gs: *Game) {
    controller.poll()
    let pad = controller.read(0)

    -- player movement
    if pad.held.left and gs.player.x > 0 {
        gs.player.x = gs.player.x - PLAYER_SPEED
    }
    if pad.held.right and gs.player.x < SCREEN_W - PLAYER_SIZE {
        gs.player.x = gs.player.x + PLAYER_SPEED
    }
    if pad.held.up and gs.player.y > 0 {
        gs.player.y = gs.player.y - PLAYER_SPEED
    }
    if pad.held.down and gs.player.y < SCREEN_H - PLAYER_SIZE {
        gs.player.y = gs.player.y + PLAYER_SPEED
    }

    -- fire
    if pad.pressed.a {
        spawn_bullet(gs)
    }

    -- spawn enemies
    gs.spawn_timer = gs.spawn_timer + 1
    if gs.spawn_timer >= 30 {
        gs.spawn_timer = 0
        spawn_enemy(gs)
    }

    -- update bullets
    for i in 0..MAX_BULLETS {
        if not gs.bullets[i].active { continue }
        gs.bullets[i].y = gs.bullets[i].y - BULLET_SPEED
        if gs.bullets[i].y < -BULLET_SIZE {
            gs.bullets[i].active = false
        }
    }

    -- update enemies
    for i in 0..MAX_ENEMIES {
        if not gs.enemies[i].active { continue }
        gs.enemies[i].y = gs.enemies[i].y + ENEMY_SPEED
        if gs.enemies[i].y > SCREEN_H {
            gs.enemies[i].active = false
        }
    }

    -- bullet-enemy collision
    for b in 0..MAX_BULLETS {
        if not gs.bullets[b].active { continue }
        for e in 0..MAX_ENEMIES {
            if not gs.enemies[e].active { continue }
            if gs.bullets[b].x + BULLET_SIZE >= gs.enemies[e].x {
                if gs.bullets[b].x <= gs.enemies[e].x + ENEMY_SIZE {
                    if gs.bullets[b].y + BULLET_SIZE >= gs.enemies[e].y {
                        if gs.bullets[b].y <= gs.enemies[e].y + ENEMY_SIZE {
                            gs.bullets[b].active = false
                            gs.enemies[e].active = false
                            gs.score = gs.score + 10
                        }
                    }
                }
            }
        }
    }
}

fn render(gs: *Game) {
    let fb = display.get()
    rdpq.attach_clear(fb)

    rdpq.set_mode_fill(COLOR_BG)
    rdpq.fill_rectangle(0, 0, SCREEN_W, SCREEN_H)

    -- player
    rdpq.sync_pipe()
    rdpq.set_mode_fill(COLOR_PLAYER)
    rdpq.fill_rectangle(gs.player.x, gs.player.y, gs.player.x + PLAYER_SIZE, gs.player.y + PLAYER_SIZE)

