struct Cooldown {
    elapsed: fix16.16
    duration: fix16.16
    ready: bool
}

impl Cooldown {
    fn init(self: *Cooldown, duration: fix16.16) {
        self.elapsed = 0.0 as fix16.16
        self.duration = duration
        self.ready = true
    }

    fn update(self: *Cooldown, dt: fix16.16) {
        if self.ready { return }
        self.elapsed = self.elapsed + dt
        if self.elapsed >= self.duration {
            self.ready = true
        }
    }

    fn trigger(self: *Cooldown) -> bool {
        if not self.ready { return false }
        self.ready = false
        self.elapsed = 0.0 as fix16.16
        return true
    }
}
