The mixer is a software audio mixing engine that runs on the RSP. It mixes multiple channels of audio into a single stereo output.

Setup in Pak:
```pak
use n64.audio

extern "C" {
    fn mixer_init(num_channels: i32)
    fn mixer_close()
    fn mixer_poll(out: *i16, nsamples: i32)
    fn mixer_set_vol(vol: f32)
    fn mixer_ch_set_vol(ch: i32, lvol: f32, rvol: f32)
    fn mixer_ch_set_vol_pan(ch: i32, vol: f32, pan: f32)
    fn mixer_ch_play(ch: i32, wave: *waveform_t)
    fn mixer_ch_stop(ch: i32)
    fn mixer_ch_playing(ch: i32) -> bool
    fn mixer_ch_set_freq(ch: i32, freq: f32)
}

entry {
    audio.init(44100, 4)
    mixer_init(8)  -- 8 channels

    loop {
        -- mixer_poll fills audio buffers automatically
        -- when using wav64/xm64, mixer handles the output
        let buf: *i16 = audio.get_buffer()
        if buf != none {
            mixer_poll(buf, 735)  -- 44100/60 = 735 samples
        }
    }
}
```

Channel count doesn't affect performance until channels are actually playing.

