The critical audio loop pattern:

```pak
use n64.audio

extern "C" {
    fn mixer_poll(out: *i16, nsamples: i32)
    fn audio_get_buffer_length() -> i32
}

fn audio_frame() {
    -- get buffer length (varies by frequency and TV type)
    let nsamples: i32 = audio_get_buffer_length()

    let buf: *i16 = audio.get_buffer()
    if buf == none { return }  -- always check

    mixer_poll(buf, nsamples)  -- fills stereo interleaved
}
```

Call `audio_frame()` every frame in your game loop. `audio_get_buffer_length()` returns the correct sample count for the current frequency and TV type (PAL vs NTSC).

N64 hardware is stereo only, but you can fake 3D audio with panning and volume:

```pak
extern "C" {
    fn mixer_ch_set_vol_pan(ch: i32, vol: f32, pan: f32)
}

fn update_3d_sound(ch: i32, listener_x: f32, listener_y: f32,
                   source_x: f32, source_y: f32) {
    let dx: f32 = source_x - listener_x
    let dy: f32 = source_y - listener_y
    let dist_sq: f32 = dx * dx + dy * dy

    -- volume falls off with distance squared
    let max_dist_sq: f32 = 10000.0
    let vol: f32 = 1.0 - dist_sq / max_dist_sq
    if vol < 0.0 { vol = 0.0 }

    -- pan based on x offset (-1 to 1 mapped to 0 to 1)
    let pan: f32 = (dx / 100.0) + 0.5
    if pan < 0.0 { pan = 0.0 }
    if pan > 1.0 { pan = 1.0 }

    mixer_ch_set_vol_pan(ch, vol, pan)
}
```

