```pak
use t3d

struct ThirdPersonCamera {
    target_x: f32
    target_y: f32
    target_z: f32
    distance: f32
    pitch: f32
    yaw: f32
    x: f32
    y: f32
    z: f32
}

impl ThirdPersonCamera {
    fn init(self: *ThirdPersonCamera) {
        self.distance = 15.0
        self.pitch = 0.3
        self.yaw = 0.0
    }

    fn update(self: *ThirdPersonCamera, tx: f32, ty: f32, tz: f32,
              stick_x: f32, stick_y: f32, dt: f32) {
        self.target_x = tx
        self.target_y = ty
        self.target_z = tz

        -- rotate camera with analog stick
        self.yaw = self.yaw + stick_x * dt * 2.0
        self.pitch = self.pitch + stick_y * dt * 1.0
        if self.pitch < 0.1 { self.pitch = 0.1 }
        if self.pitch > 1.2 { self.pitch = 1.2 }

        -- compute camera position on sphere around target
        -- simplified: uses pitch as elevation, yaw as rotation
        self.x = tx + self.distance * self.pitch * self.yaw
        self.y = ty + self.distance * self.pitch
        self.z = tz + self.distance * self.pitch
    }

    fn get_view_matrix(self: *ThirdPersonCamera, out: *T3DMat4) {
        t3d.mat4_identity(out)
        t3d.mat4_rotate_y(out, -self.yaw)
        t3d.mat4_rotate_x(out, -self.pitch)
        t3d.mat4_translate(out, -self.x, -self.y, -self.z)
    }
}
```

```pak
use t3d

struct FPSCamera {
    x: f32
    y: f32
    z: f32
    yaw: f32
    pitch: f32
    move_speed: f32
    look_speed: f32
}

impl FPSCamera {
    fn init(self: *FPSCamera) {
        self.x = 0.0
        self.y = 2.0
        self.z = 0.0
        self.yaw = 0.0
        self.pitch = 0.0
        self.move_speed = 10.0
        self.look_speed = 2.0
    }

    fn update(self: *FPSCamera, pad: *controller_data, dt: f32) {
        -- look with C buttons
        if pad.held.c_left { self.yaw = self.yaw + self.look_speed * dt }
        if pad.held.c_right { self.yaw = self.yaw - self.look_speed * dt }
        if pad.held.c_up { self.pitch = self.pitch + self.look_speed * dt }
        if pad.held.c_down { self.pitch = self.pitch - self.look_speed * dt }

        -- clamp pitch
        if self.pitch > 1.2 { self.pitch = 1.2 }
        if self.pitch < -1.2 { self.pitch = -1.2 }

        -- move with analog stick (relative to facing)
        let sx: i32 = pad.stick_x as i32
        let sy: i32 = pad.stick_y as i32
        let fx: f32 = (sx as f32) / 80.0
        let fy: f32 = (sy as f32) / 80.0

        self.z = self.z + fy * self.move_speed * dt
        self.x = self.x + fx * self.move_speed * dt
    }

    fn get_view_matrix(self: *FPSCamera, out: *T3DMat4) {
        t3d.mat4_identity(out)
        t3d.mat4_rotate_x(out, -self.pitch)
        t3d.mat4_rotate_y(out, -self.yaw)
        t3d.mat4_translate(out, -self.x, -self.y, -self.z)
    }
}
