use t3d

const MAX_ENTITIES: i32 = 32

struct Entity3D {
    active: bool
    model: *T3DModel
    x: f32
    y: f32
    z: f32
    rot_y: f32
    scale: f32
    mat: T3DMat4
}

static entities: [Entity3D; 32] = undefined
static entity_count: i32 = 0

fn spawn_entity(model: *T3DModel, x: f32, y: f32, z: f32) -> i32 {
    if entity_count >= MAX_ENTITIES { return -1 }
    let idx: i32 = entity_count
    entities[idx].active = true
    entities[idx].model = model
    entities[idx].x = x
    entities[idx].y = y
    entities[idx].z = z
    entities[idx].rot_y = 0.0
    entities[idx].scale = 1.0
    t3d.mat4_identity(&entities[idx].mat)
    entity_count = entity_count + 1
    return idx
}

fn update_entity_matrices() {
    let i: i32 = 0
    loop {
        if i >= entity_count { break }
        if entities[i].active {
            let tmp: T3DMat4 = undefined
            t3d.mat4_identity(&entities[i].mat)
            t3d.mat4_scale(&entities[i].mat, entities[i].scale,
                           entities[i].scale, entities[i].scale)
            t3d.mat4_rotate_y(&tmp, entities[i].rot_y)
            t3d.mat4_mul(&entities[i].mat, &entities[i].mat, &tmp)
            t3d.mat4_translate(&tmp, entities[i].x, entities[i].y, entities[i].z)
            t3d.mat4_mul(&entities[i].mat, &entities[i].mat, &tmp)
        }
        i = i + 1
    }
}

fn draw_all_entities() {
    let i: i32 = 0
    loop {
        if i >= entity_count { break }
        if entities[i].active {
            t3d.model_draw(entities[i].model)
        }
        i = i + 1
    }
}
