T3D doesn't have built-in LOD. Implement manually with distance checks:

```pak
use t3d

struct LODModel {
    high: *T3DModel    -- close range
    medium: *T3DModel  -- mid range
    low: *T3DModel     -- far range
    lod_dist_med: f32  -- switch to medium at this distance
    lod_dist_low: f32  -- switch to low at this distance
}

fn draw_lod(lod: *LODModel, cam_x: f32, cam_z: f32,
            obj_x: f32, obj_z: f32) {
    let dx: f32 = cam_x - obj_x
    let dz: f32 = cam_z - obj_z
    let dist_sq: f32 = dx * dx + dz * dz

    if dist_sq > lod.lod_dist_low * lod.lod_dist_low {
        t3d.model_draw(lod.low)
    } elif dist_sq > lod.lod_dist_med * lod.lod_dist_med {
        t3d.model_draw(lod.medium)
    } else {
        t3d.model_draw(lod.high)
    }
}
```

Use squared distance to avoid expensive square root. 3 LOD levels is usually enough for N64.

