Do a simple distance + angle check before drawing:

```pak
use t3d

fn is_visible(cam_x: f32, cam_z: f32, cam_yaw: f32,
              obj_x: f32, obj_z: f32, max_dist: f32) -> bool {
    let dx: f32 = obj_x - cam_x
    let dz: f32 = obj_z - cam_z
    let dist_sq: f32 = dx * dx + dz * dz

    -- distance check
    if dist_sq > max_dist * max_dist { return false }

    -- rough angle check (dot product with view direction)
    -- objects behind camera are culled
    let view_z: f32 = 1.0  -- simplified forward vector
    let dot: f32 = dx * 0.0 + dz * view_z
    if dot < 0.0 { return false }  -- behind camera

    return true
}

-- in render loop:
let i: i32 = 0
loop {
    if i >= entity_count { break }
    if is_visible(cam.x, cam.z, cam.yaw,
                  entities[i].x, entities[i].z, 100.0) {
        t3d.model_draw(entities[i].model)
    }
    i = i + 1
}
```

This is a rough cull. For complex scenes, use sector-based visibility or BSP trees. Even a simple distance cull saves significant GPU time.

