```pak
enum AIState { idle, patrol, chase, attack, flee, dead }

struct Enemy {
    x: f32
    y: f32
    z: f32
    hp: i32
    state: AIState
    patrol_x: f32
    patrol_z: f32
    target_x: f32
    target_z: f32
    state_timer: f32
    attack_cooldown: f32
}

fn ai_update(e: *Enemy, player_x: f32, player_z: f32, dt: f32) {
    let dx: f32 = player_x - e.x
    let dz: f32 = player_z - e.z
    let dist_sq: f32 = dx * dx + dz * dz
    e.state_timer = e.state_timer + dt
    e.attack_cooldown = e.attack_cooldown - dt
    if e.attack_cooldown < 0.0 { e.attack_cooldown = 0.0 }

    match e.state {
        AIState.idle => {
            if dist_sq < 2500.0 { e.state = AIState.chase }
            if e.state_timer > 3.0 {
                e.state = AIState.patrol
                e.state_timer = 0.0
            }
        }
        AIState.patrol => {
            -- move toward patrol point
            let px: f32 = e.patrol_x - e.x
            let pz: f32 = e.patrol_z - e.z
            e.x = e.x + px * 0.02
            e.z = e.z + pz * 0.02
            if dist_sq < 2500.0 { e.state = AIState.chase }
            if px * px + pz * pz < 4.0 {
                e.state = AIState.idle
                e.state_timer = 0.0
            }
        }
        AIState.chase => {
            e.x = e.x + dx * 0.03
            e.z = e.z + dz * 0.03
            if dist_sq < 100.0 and e.attack_cooldown <= 0.0 {
                e.state = AIState.attack
                e.state_timer = 0.0
            }
            if dist_sq > 10000.0 {
                e.state = AIState.idle
                e.state_timer = 0.0
            }
        }
        AIState.attack => {
            if e.state_timer > 0.5 {
                e.attack_cooldown = 2.0
                e.state = AIState.chase
                e.state_timer = 0.0
            }
        }
        AIState.flee => {
            e.x = e.x - dx * 0.04
            e.z = e.z - dz * 0.04
        }
        AIState.dead => { }
    }

    if e.hp <= 0 { e.state = AIState.dead }
    if e.hp < 3 and e.state != AIState.dead {
        e.state = AIState.flee
    }
}
```

```pak
struct AABB {
    min_x: f32
    min_y: f32
    min_z: f32
    max_x: f32
    max_y: f32
    max_z: f32
}

fn aabb_overlap(a: *AABB, b: *AABB) -> bool {
    if a.max_x < b.min_x or a.min_x > b.max_x { return false }
    if a.max_y < b.min_y or a.min_y > b.max_y { return false }
    if a.max_z < b.min_z or a.min_z > b.max_z { return false }
    return true
}

fn aabb_from_pos(x: f32, y: f32, z: f32,
                 hw: f32, hh: f32, hd: f32, out: *AABB) {
    out.min_x = x - hw
    out.max_x = x + hw
    out.min_y = y - hh
    out.max_y = y + hh
    out.min_z = z - hd
    out.max_z = z + hd
}

fn resolve_aabb(mover: *AABB, obstacle: *AABB,
                vx: *f32, vy: *f32, vz: *f32) {
    if not aabb_overlap(mover, obstacle) { return }
    -- push out on smallest overlap axis
    let ox: f32 = mover.max_x - obstacle.min_x
    let oy: f32 = mover.max_y - obstacle.min_y
    let oz: f32 = mover.max_z - obstacle.min_z
    if ox < oy and ox < oz {
        *vx = 0.0
    } elif oy < oz {
        *vy = 0.0
    } else {
        *vz = 0.0
    }
}
```

