const MAX_ITEMS: i32 = 20
const MAX_STACK: i32 = 99

enum ItemType {
    none_item, health_potion, mana_potion, key,
    sword, shield, arrow, bomb, hookshot, boomerang
}

struct ItemSlot {
    item: ItemType
    count: i32
}

struct Inventory {
    slots: [ItemSlot; 20]
    slot_count: i32
    selected: i32
}

impl Inventory {
    fn init(self: *Inventory) {
        self.slot_count = 0
        self.selected = 0
        let i: i32 = 0
        loop {
            if i >= MAX_ITEMS { break }
            self.slots[i].item = ItemType.none_item
            self.slots[i].count = 0
            i = i + 1
        }
    }

    fn add_item(self: *Inventory, item: ItemType, count: i32) -> bool {
        -- try stacking first
        let i: i32 = 0
        loop {
            if i >= self.slot_count { break }
            if self.slots[i].item == item {
                self.slots[i].count = self.slots[i].count + count
                if self.slots[i].count > MAX_STACK {
                    self.slots[i].count = MAX_STACK
                }
                return true
            }
            i = i + 1
        }

        -- add to new slot
        if self.slot_count >= MAX_ITEMS { return false }
        self.slots[self.slot_count].item = item
        self.slots[self.slot_count].count = count
        self.slot_count = self.slot_count + 1
        return true
    }

    fn remove_item(self: *Inventory, item: ItemType, count: i32) -> bool {
        let i: i32 = 0
        loop {
            if i >= self.slot_count { break }
            if self.slots[i].item == item {
                self.slots[i].count = self.slots[i].count - count
                if self.slots[i].count <= 0 {
                    self.slots[i].item = ItemType.none_item
                    self.slots[i].count = 0
                }
                return true
            }
            i = i + 1
        }
        return false
    }

    fn has_item(self: *Inventory, item: ItemType) -> bool {
        let i: i32 = 0
        loop {
            if i >= self.slot_count { break }
            if self.slots[i].item == item and self.slots[i].count > 0 {
                return true
            }
            i = i + 1
        }
        return false
    }
}
