use n64.rdpq

const MAX_DIALOG_LEN: i32 = 128
const CHARS_PER_LINE: i32 = 28
const BOX_X: i32 = 20
const BOX_Y: i32 = 160
const BOX_W: i32 = 280
const BOX_H: i32 = 60

struct DialogBox {
    text: [c_char; 128]
    text_len: i32
    chars_shown: i32
    active: bool
    timer: f32
    speed: f32
}

impl DialogBox {
    fn init(self: *DialogBox) {
        self.active = false
        self.chars_shown = 0
        self.timer = 0.0
        self.speed = 15.0  -- chars/second
    }

    fn show(self: *DialogBox, msg: *c_char, len: i32) {
        let i: i32 = 0
        loop {
            if i >= len or i >= MAX_DIALOG_LEN - 1 { break }
            self.text[i] = msg[i]
            i = i + 1
        }
        self.text[i] = 0 as c_char
        self.text_len = len
        self.chars_shown = 0
        self.active = true
        self.timer = 0.0
    }

    fn update(self: *DialogBox, dt: f32, a_pressed: bool) {
        if not self.active { return }
        if self.chars_shown < self.text_len {
            self.timer = self.timer + self.speed * dt
            self.chars_shown = self.timer as i32
            if self.chars_shown > self.text_len {
                self.chars_shown = self.text_len
            }
            -- A button shows all text immediately
            if a_pressed { self.chars_shown = self.text_len }
        } else {
            -- all text shown, A closes dialog
            if a_pressed { self.active = false }
        }
    }

    fn draw(self: *DialogBox) {
        if not self.active { return }
        -- draw box background
        rdpq.set_mode_fill(0x000000C0)  -- semi-transparent black
        rdpq.fill_rectangle(BOX_X, BOX_Y, BOX_X + BOX_W, BOX_Y + BOX_H)
        -- text would be drawn with rdpq_font here
    }
}
