const MAX_ROOMS: i32 = 16
const MAX_DOORS: i32 = 4

struct Door {
    x: f32
    z: f32
    width: f32
    target_room: i32
    spawn_x: f32
    spawn_z: f32
}

struct Room {
    active: bool
    model_path: *c_char
    model: *T3DModel
    doors: [Door; 4]
    door_count: i32
    enemy_start: i32
    enemy_count: i32
}

static rooms: [Room; 16] = undefined
static current_room: i32 = 0

fn load_room(idx: i32) {
    -- unload previous room
    if rooms[current_room].model != none {
        t3d.model_free(rooms[current_room].model)
        rooms[current_room].model = none
    }

    -- load new room
    rooms[idx].model = t3d.model_load(rooms[idx].model_path)
    current_room = idx
}

fn check_doors(player_x: f32, player_z: f32) {
    let room: *Room = &rooms[current_room]
    let i: i32 = 0
    loop {
        if i >= room.door_count { break }
        let door: *Door = &room.doors[i]
        let dx: f32 = player_x - door.x
        let dz: f32 = player_z - door.z
        if dx * dx + dz * dz < door.width * door.width {
            load_room(door.target_room)
            -- teleport player to spawn point
            return
        }
        i = i + 1
    }
}
```

Only one room model is loaded at a time to conserve memory. Doors trigger room transitions with spawn points.

```pak
const MAX_WEAPONS: i32 = 8

enum WeaponType {
    none_weapon, pistol, shotgun, rifle, rocket_launcher,
    sniper, grenade, melee
}

struct WeaponDef {
    wtype: WeaponType
    damage: i32
    fire_rate: f32
    ammo_max: i32
    range: f32
    spread: f32
    is_automatic: bool
}

struct WeaponState {
    def: *WeaponDef
    ammo: i32
    cooldown: f32
    reloading: bool
    reload_timer: f32
}

struct WeaponInventory {
    weapons: [WeaponState; 8]
    count: i32
    current: i32
}

fn weapon_fire(ws: *WeaponState) -> bool {
    if ws.cooldown > 0.0 { return false }
    if ws.ammo <= 0 { return false }
    if ws.reloading { return false }

    ws.ammo = ws.ammo - 1
    ws.cooldown = ws.def.fire_rate
    return true
}

fn weapon_update(ws: *WeaponState, dt: f32) {
    if ws.cooldown > 0.0 {
        ws.cooldown = ws.cooldown - dt
    }
    if ws.reloading {
        ws.reload_timer = ws.reload_timer - dt
        if ws.reload_timer <= 0.0 {
            ws.ammo = ws.def.ammo_max
            ws.reloading = false
        }
    }
}

fn weapon_switch(inv: *WeaponInventory, dir: i32) {
    inv.current = inv.current + dir
    if inv.current >= inv.count { inv.current = 0 }
    if inv.current < 0 { inv.current = inv.count - 1 }
}
