const MAX_OBJECTIVES: i32 = 8

enum ObjectiveState { locked, active, completed, failed }

struct Objective {
    name: *c_char
    description: *c_char
    state: ObjectiveState
    required: bool  -- must complete to win
}

struct Mission {
    objectives: [Objective; 8]
    count: i32
}

impl Mission {
    fn complete_objective(self: *Mission, idx: i32) {
        if idx >= 0 and idx < self.count {
            self.objectives[idx].state = ObjectiveState.completed
        }
    }

    fn fail_objective(self: *Mission, idx: i32) {
        if idx >= 0 and idx < self.count {
            self.objectives[idx].state = ObjectiveState.failed
        }
    }

    fn is_mission_complete(self: *Mission) -> bool {
        let i: i32 = 0
        loop {
            if i >= self.count { break }
            if self.objectives[i].required {
                if self.objectives[i].state != ObjectiveState.completed {
                    return false
                }
            }
            i = i + 1
        }
        return true
    }

    fn is_mission_failed(self: *Mission) -> bool {
        let i: i32 = 0
        loop {
            if i >= self.count { break }
            if self.objectives[i].required {
                if self.objectives[i].state == ObjectiveState.failed {
                    return true
                }
            }
            i = i + 1
        }
        return false
    }
}
