const MAX_ENEMIES: i32 = 16

struct SpawnWave {
    enemy_count: i32
    spawn_delay: f32
    spawned: i32
    timer: f32
}

struct SpawnSystem {
    waves: [SpawnWave; 8]
    wave_count: i32
    current_wave: i32
    enemies_alive: i32
}

impl SpawnSystem {
    fn update(self: *SpawnSystem, dt: f32) {
        if self.current_wave >= self.wave_count { return }

        let wave: *SpawnWave = &self.waves[self.current_wave]
        wave.timer = wave.timer + dt

        if wave.timer >= wave.spawn_delay and wave.spawned < wave.enemy_count {
            -- spawn an enemy
            wave.spawned = wave.spawned + 1
            wave.timer = 0.0
            self.enemies_alive = self.enemies_alive + 1
        }

        -- advance wave when all enemies defeated
        if wave.spawned >= wave.enemy_count and self.enemies_alive <= 0 {
            self.current_wave = self.current_wave + 1
        }
    }
}
